query:
{
  vms(
    where: {
      NOT: { publicIpAddress: { eq: null } }
      securityGroups_SOME: {
        rules_SOME: {
          direction: { eq: "Inbound" }
          action: { eq: "Allow" }
          AND: [
            {
              OR: [
                { sources_INCLUDES: "cidr:0.0.0.0/0" }
                { sources_INCLUDES: "cidr:::/0" }
              ]
            }
            {
              OR: [
                { destFromPort_LTE: 22, destToPort_GTE: 22 }
                { destFromPort_LTE: 3389, destToPort_GTE: 3389 }
              ]
            }
          ]
        }
      }
    }
  ) {
    ...AssetFragment
  }
}
